import{_ as s,o as a,c as n,ag as t}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"Design Spec: Permission Dialogs","description":"","frontmatter":{},"headers":[],"relativePath":"design-spec/07_permission_dialogs.md","filePath":"design-spec/07_permission_dialogs.md","lastUpdated":1775248729000}'),o={name:"design-spec/07_permission_dialogs.md"};function i(d,e,l,r,p,c){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="design-spec-permission-dialogs" tabindex="-1">Design Spec: Permission Dialogs <a class="header-anchor" href="#design-spec-permission-dialogs" aria-label="Permalink to &quot;Design Spec: Permission Dialogs&quot;">​</a></h1><p><strong>TS source</strong>: <code>components/permissions/</code>, <code>components/PermissionRequest.tsx</code></p><hr><h2 id="standard-permission-dialog" tabindex="-1">Standard Permission Dialog <a class="header-anchor" href="#standard-permission-dialog" aria-label="Permalink to &quot;Standard Permission Dialog&quot;">​</a></h2><p>Shown when a tool call requires user approval.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭──────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│  PikoClaw wants to run a command                         │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  bash                                                    │</span></span>
<span class="line"><span>│  rm -rf ./node_modules &amp;&amp; npm install                    │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  [ Yes (y) ]  [ No (n) ]  [ Always (a) ]  [ Never (d) ] │</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="layout-details" tabindex="-1">Layout details <a class="header-anchor" href="#layout-details" aria-label="Permalink to &quot;Layout details&quot;">​</a></h3><ul><li><strong>Border</strong>: rounded, color <code>theme.permission</code> (blue)</li><li><strong>Width</strong>: min 40, max 80 chars (capped to terminal width)</li><li><strong>Position</strong>: above the input bar, replacing the bottom section</li><li><strong>Header line</strong>: <code>theme.inactive</code> dimmed text</li><li><strong>Tool name</strong>: <code>theme.text</code> bold</li><li><strong>Input preview</strong>: see section below</li><li><strong>Button row</strong>: horizontal, separated by 2 spaces</li></ul><h3 id="button-design" tabindex="-1">Button design <a class="header-anchor" href="#button-design" aria-label="Permalink to &quot;Button design&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ Yes (y) ]   [ No (n) ]   [ Always (a) ]   [ Never (d) ]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><table tabindex="0"><thead><tr><th>Button</th><th>Key</th><th>Color</th><th>Behavior</th></tr></thead><tbody><tr><td>Yes</td><td><code>y</code></td><td><code>theme.permission</code> (blue)</td><td>Allow once</td></tr><tr><td>No</td><td><code>n</code></td><td><code>theme.error</code> (red)</td><td>Deny once</td></tr><tr><td>Always</td><td><code>a</code></td><td><code>theme.success</code> (green)</td><td>Allow for all future calls this session</td></tr><tr><td>Never</td><td><code>d</code></td><td><code>theme.error</code> dim</td><td>Deny all future calls this session</td></tr></tbody></table><p><strong>Focused button</strong>: inverted colors (white text on colored bg). Initial focus: <code>Yes</code> button.</p><p>Navigation: <code>←/→</code> or <code>Tab</code> to move between buttons, <code>Enter</code> to confirm focused. Direct hotkey: press <code>y</code>/<code>n</code>/<code>a</code>/<code>d</code> immediately (no need to navigate to button).</p><hr><h2 id="tool-input-preview" tabindex="-1">Tool Input Preview <a class="header-anchor" href="#tool-input-preview" aria-label="Permalink to &quot;Tool Input Preview&quot;">​</a></h2><p>Below the tool name, show the most relevant input field:</p><h3 id="bash-tool" tabindex="-1">bash tool <a class="header-anchor" href="#bash-tool" aria-label="Permalink to &quot;bash tool&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  bash</span></span>
<span class="line"><span>  rm -rf ./node_modules &amp;&amp; npm install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Color rules for bash commands:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Color</th></tr></thead><tbody><tr><td>Contains <code>rm</code>, <code>rmdir</code>, <code>del</code>, <code>unlink</code></td><td><code>theme.error</code> (red)</td></tr><tr><td>Contains <code>sudo</code>, <code>su</code>, <code>chmod 777</code></td><td><code>theme.warning</code> (amber)</td></tr><tr><td>Contains <code>curl | bash</code>, <code>eval</code>, <code>exec</code></td><td><code>theme.warning</code> (amber)</td></tr><tr><td>Safe read-only: <code>ls</code>, <code>cat</code>, <code>grep</code>, <code>git status</code></td><td><code>theme.inactive</code> (dim)</td></tr><tr><td>Default</td><td><code>theme.text</code> (normal)</td></tr></tbody></table><h3 id="file-write-file-edit-tool" tabindex="-1">file_write / file_edit tool <a class="header-anchor" href="#file-write-file-edit-tool" aria-label="Permalink to &quot;file_write / file_edit tool&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  file_edit</span></span>
<span class="line"><span>  src/auth/jwt.rs</span></span>
<span class="line"><span>  replacing: &quot;claims.exp &lt; &quot; → &quot;claims.exp &lt;= &quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Show: <code>file_path</code> + brief description of change.</p><h3 id="file-read-tool" tabindex="-1">file_read tool <a class="header-anchor" href="#file-read-tool" aria-label="Permalink to &quot;file_read tool&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  file_read</span></span>
<span class="line"><span>  /etc/passwd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Color path red if it&#39;s a system path (<code>/etc/</code>, <code>/sys/</code>, <code>/proc/</code>, <code>~/.ssh/</code>, etc.).</p><h3 id="web-fetch-web-search-tool" tabindex="-1">web_fetch / web_search tool <a class="header-anchor" href="#web-fetch-web-search-tool" aria-label="Permalink to &quot;web_fetch / web_search tool&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  web_fetch</span></span>
<span class="line"><span>  https://api.internal.example.com/admin/users</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="agent-tool" tabindex="-1">agent tool <a class="header-anchor" href="#agent-tool" aria-label="Permalink to &quot;agent tool&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  agent</span></span>
<span class="line"><span>  &quot;Analyze the authentication system and suggest improvements&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Show truncated prompt (first 80 chars).</p><hr><h2 id="dangerous-operation-emphasis" tabindex="-1">Dangerous Operation Emphasis <a class="header-anchor" href="#dangerous-operation-emphasis" aria-label="Permalink to &quot;Dangerous Operation Emphasis&quot;">​</a></h2><p>When the operation is considered dangerous, add a warning header:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭──────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│  ⚠  This command may delete files                        │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  bash                                                    │</span></span>
<span class="line"><span>│  rm -rf ./build ./dist                                   │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  [ Yes (y) ]  [ No (n) ]  [ Always (a) ]  [ Never (d) ] │</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><ul><li><strong>Warning icon</strong> <code>⚠</code>: <code>theme.warning</code> (amber)</li><li><strong>Warning text</strong>: <code>theme.warning</code></li><li><strong>Border color</strong>: <code>theme.warning</code> instead of <code>theme.permission</code></li></ul><p>Dangerous patterns:</p><ul><li><code>rm -rf</code> / <code>del /s /q</code> — file deletion</li><li>Writing to <code>/etc/</code>, <code>/System/</code>, <code>C:\\Windows\\</code> — system paths</li><li><code>DROP TABLE</code>, <code>DELETE FROM</code> — database destruction</li><li><code>git push --force</code> to main/master</li><li>Commands reading sensitive files: <code>~/.ssh/id_rsa</code>, <code>~/.aws/credentials</code></li></ul><hr><h2 id="question-dialog-askuserquestion-tool" tabindex="-1">Question Dialog (AskUserQuestion tool) <a class="header-anchor" href="#question-dialog-askuserquestion-tool" aria-label="Permalink to &quot;Question Dialog (AskUserQuestion tool)&quot;">​</a></h2><p>When the agent calls <code>AskUserQuestionTool</code>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭──────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│  Which approach should I use?                            │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  1. Refactor the existing JWT implementation             │</span></span>
<span class="line"><span>│  2. Replace with a third-party library (jsonwebtoken)    │</span></span>
<span class="line"><span>│  3. Use Anthropic&#39;s built-in auth (if available)         │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  Enter number or type your answer: _                     │</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><ul><li><strong>Border</strong>: rounded, <code>theme.permission</code> (blue)</li><li><strong>Question</strong>: <code>theme.text</code>, first line bold</li><li><strong>Options</strong>: numbered list, <code>theme.text</code></li><li><strong>Input line</strong>: standard text input at bottom of dialog</li><li><strong>Navigation</strong>: type <code>1</code>/<code>2</code>/<code>3</code> to select, or type free text, then Enter</li></ul><p>If no options provided (free-form question):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭──────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│  What&#39;s your preferred test framework?                   │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  &gt; _                                                     │</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="plan-mode-exit-dialog" tabindex="-1">Plan Mode Exit Dialog <a class="header-anchor" href="#plan-mode-exit-dialog" aria-label="Permalink to &quot;Plan Mode Exit Dialog&quot;">​</a></h2><p>When agent calls <code>ExitPlanModeTool</code>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭──────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│  Agent wants to exit plan mode and make changes          │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  The agent will now be able to run commands and          │</span></span>
<span class="line"><span>│  modify files.                                           │</span></span>
<span class="line"><span>│                                                          │</span></span>
<span class="line"><span>│  [ Allow (y) ]          [ Keep planning (n) ]            │</span></span>
<span class="line"><span>╰──────────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><ul><li><strong>Border</strong>: <code>theme.warning</code> (amber) — signals a mode change</li><li><strong>Allow</strong>: <code>theme.success</code> (green)</li><li><strong>Keep planning</strong>: <code>theme.inactive</code></li></ul><hr><h2 id="keyboard-shortcuts-summary" tabindex="-1">Keyboard Shortcuts Summary <a class="header-anchor" href="#keyboard-shortcuts-summary" aria-label="Permalink to &quot;Keyboard Shortcuts Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>In permission dialog</th><th>In question dialog</th></tr></thead><tbody><tr><td><code>y</code></td><td>Allow once</td><td>—</td></tr><tr><td><code>n</code></td><td>Deny once</td><td>—</td></tr><tr><td><code>a</code></td><td>Always allow</td><td>—</td></tr><tr><td><code>d</code></td><td>Always deny</td><td>—</td></tr><tr><td><code>←</code> / <code>→</code></td><td>Navigate buttons</td><td>—</td></tr><tr><td><code>Tab</code></td><td>Navigate buttons</td><td>—</td></tr><tr><td><code>Enter</code></td><td>Confirm focused</td><td>Submit answer</td></tr><tr><td><code>Esc</code></td><td>Deny (same as <code>n</code>)</td><td>Cancel</td></tr><tr><td><code>1</code>–<code>9</code></td><td>—</td><td>Select numbered option</td></tr></tbody></table>`,53)])])}const b=s(o,[["render",i]]);export{u as __pageData,b as default};
